            // Google often sends "retryDelay": "12.34s" in error details
            let retryAfter = 60; // Default 1 min
            const match = error.message?.match(/retryDelay[:\s]+"?(\d+(\.\d+)?)s"?/);
            if (match) {
                retryAfter = Math.ceil(parseFloat(match[1]));
            }

            return {
