import { GoogleAICacheManager, GoogleAIFileManager } from '@google/generative-ai/server';
import { env } from '$env/dynamic/private';
import { createHash } from 'crypto';

// Cache configuration
const CACHE_BASE_NAME = 'lineum-core-v1';
const CACHE_TTL_SECONDS = 3600; // 1 hour (Free tier limit usually)
const MODEL_NAME = 'models/gemini-1.5-flash-002'; // Stable 1.5 works with caching on Free Tier

// Singleton instance
let cacheManager: GoogleAICacheManager | null = null;
let fileManager: GoogleAIFileManager | null = null;

function getCacheManager() {
    if (!cacheManager) {
        if (!env.GEMINI_API_KEY) throw new Error("GEMINI_API_KEY not found in environment");
        cacheManager = new GoogleAICacheManager(env.GEMINI_API_KEY);
    }
    return cacheManager;
}

// In-memory cache of the active cache name to avoid API calls on every request
// keys: displayName -> { name: string, expires: number }
const localRefCache: Record<string, { name: string, expires: number }> = {};

/**
 * Gets a valid cache name (resource ID) for the given content.
 * Automatically invalidates if content changes (via hash in displayName).
 */
export async function getOrUpdateCache(content: string, mimeType = 'text/plain'): Promise<string> {
    const mgr = getCacheManager();

    // Generate hash of content to detect changes
    const hash = createHash('sha256').update(content).digest('hex').substring(0, 8);
    const currentDisplayName = `${CACHE_BASE_NAME}-${hash}`;

    // 1. Check local ref first (fast path)
    const now = Date.now();
    if (localRefCache[currentDisplayName]) {
        if (localRefCache[currentDisplayName].expires > now + 300000) { // 5 mins safety buffer
            return localRefCache[currentDisplayName].name;
        } else {
            // Expired or close to expiry, clear local ref
            delete localRefCache[currentDisplayName];
        }
    }

    try {
        // 2. List existing caches to find ours
        // Note: list() is paginated but we assume we don't have thousands
        const listResult = await mgr.list();

        let existingCache = null;

        if (listResult.cachedContents) {
            for (const c of listResult.cachedContents) {
                if (c.displayName === currentDisplayName) {
                    // Start strict: Matches content hash AND not expired
                    if (c.name && c.expireTime) {
                        const expiryTime = new Date(c.expireTime).getTime();
                        if (expiryTime > now + 300000) {
                            existingCache = c;
                            break;
                        } else {
                            // Expired exact match
                            console.log(`[GeminiCache] Deleting expired: ${c.name}`);
                            try { await mgr.delete(c.name); } catch (e) { }
                        }
                    }
                } else if (c.displayName && c.displayName.startsWith(CACHE_BASE_NAME)) {
                    // Old version of our cache (different hash) -> Cleanup
                    // We only clean up if we are sure it's ours and old
                    console.log(`[GeminiCache] Cleanup old version: ${c.displayName}`);
                    if (c.name) {
                        try { await mgr.delete(c.name); } catch (e) { }
                    }
                }
            }
        }

        if (existingCache && existingCache.name && existingCache.expireTime) {
            console.log(`[GeminiCache] Found active cache: ${existingCache.name} (${currentDisplayName})`);
            localRefCache[currentDisplayName] = {
                name: existingCache.name,
                expires: new Date(existingCache.expireTime).getTime()
            };
            return existingCache.name;
        }

        // 3. Create new cache
        console.log(`[GeminiCache] Creating new cache '${currentDisplayName}'...`);
        const newCache = await mgr.create({
            model: MODEL_NAME,
            displayName: currentDisplayName,
            ttlSeconds: CACHE_TTL_SECONDS,
            contents: [
                {
                    role: 'user',
                    parts: [{ text: content }]
                }
            ]
        });

        if (!newCache.name || !newCache.expireTime) {
            throw new Error("Cache created but missing name or expiry");
        }

        console.log(`[GeminiCache] Created: ${newCache.name}`);
        localRefCache[currentDisplayName] = {
            name: newCache.name,
            expires: new Date(newCache.expireTime).getTime()
        };

        return newCache.name;

    } catch (error) {
        console.error("[GeminiCache] Error managing cache:", error);
        throw error;
    }
}

export function resetLocalRefCache() {
    for (const key in localRefCache) {
        delete localRefCache[key];
    }
}

interface RequestLog {
    timestamp: number;
    ip: string;
}

interface LimitConfig {
    globalLimit: number; // Max requests per minute globally
    userLimit: number;   // Max requests per minute per IP
    windowMs: number;    // Time window in milliseconds
}

const DEFAULT_CONFIG: LimitConfig = {
    globalLimit: 15,
    userLimit: 5,
    windowMs: 60 * 1000
};

// Distinct configurations for different actions
export const LIMITS: Record<string, LimitConfig> = {
    chat: {
        globalLimit: 100, // Safe buffer (API limit is 360 RPM)
        userLimit: 20,    // Allow heavy user testing
        windowMs: 60 * 1000
    },
    tts: {
        globalLimit: 100,
        userLimit: 50,
        windowMs: 60 * 1000
    }
};

export class RateLimiter {
    private logs: Record<string, RequestLog[]> = {
        chat: [],
        tts: []
    };

    /**
     * Checks if a request is allowed for a specific action bucket.
     * @param action 'chat' | 'tts'
     * @param ip User IP address
     */
    check(action: string, ip: string): { allowed: boolean; reason?: string } {
        const config = LIMITS[action] || DEFAULT_CONFIG;
        const now = Date.now();

        // Ensure bucket exists
        if (!this.logs[action]) {
            this.logs[action] = [];
        }

        // 1. Clean up old logs (sliding window)
        this.logs[action] = this.logs[action].filter(log => now - log.timestamp < config.windowMs);

        const logs = this.logs[action];

        // 2. Global Limit Check
        if (logs.length >= config.globalLimit) {
            console.warn(`[LIMITER] Global limit reached for ${action}. Current: ${logs.length}, Max: ${config.globalLimit}`);
            return { allowed: false, reason: "System is busy (Global Rate Limit). Please wait a moment." };
        }

        // 3. User Limit Check
        const userLogs = logs.filter(log => log.ip === ip);
        if (userLogs.length >= config.userLimit) {
            console.warn(`[LIMITER] User limit reached for ${action} by ${ip}. Current: ${userLogs.length}, Max: ${config.userLimit}`);
            return { allowed: false, reason: "You are sending requests too fast. Please slow down." };
        }

        // 4. Record Request
        this.logs[action].push({ timestamp: now, ip });
        return { allowed: true };
    }
}

// Export a singleton instance
export const rateLimiter = new RateLimiter();

import { env } from '$env/dynamic/private';
import fs from 'fs';
import path from 'path';

const DB_FILE = 'usage_db.json';

// Pricing for Gemini 2.5 Flash (Same as 2.0 Flash)
// Input: $0.10 / 1M
// Output: $0.40 / 1M
// Cost Estimate for "Maximum Context" (Lina Persona + RAG ~15k tokens):
// ~15k * ($0.10/1M) = ~$0.0015 per request.

const COST_FLASH_INPUT = 0.10; // $0.10 / 1M
const COST_FLASH_OUTPUT = 0.40; // $0.40 / 1M

// Gemini 1.5 Pro Pricing (Approximation for 2.5 Pro Preview if billed)
// Input: $3.50 / 1M
// Output: $10.50 / 1M
const COST_PRO_INPUT = 3.50;
const COST_PRO_OUTPUT = 10.50;

interface UsageStats {
    date: string; // YYYY-MM-DD
    tokensInput: number;
    tokensOutput: number;
    estimatedCost: number;
}

export class UsageGuard {
    private stats: UsageStats = { date: '', tokensInput: 0, tokensOutput: 0, estimatedCost: 0 };
    private budgetLimitUsd: number;

    constructor() {
        // Default to $1.00 per day if not set (approx 25 CZK)
        this.budgetLimitUsd = parseFloat(env.DAILY_BUDGET_USD || '1.00');
        this.load();
    }

    private getToday(): string {
        return new Date().toISOString().split('T')[0];
    }

    private load() {
        try {
            if (fs.existsSync(DB_FILE)) {
                this.stats = JSON.parse(fs.readFileSync(DB_FILE, 'utf-8'));
            }
        } catch (e) {
            console.error("[UsageGuard] Failed to load DB:", e);
        }

        // Reset if new day
        const today = this.getToday();
        if (this.stats.date !== today) {
            console.log("[UsageGuard] New day detected. Resetting counters.");
            this.stats = { date: today, tokensInput: 0, tokensOutput: 0, estimatedCost: 0 };
            this.save();
        }
    }

    private save() {
        try {
            fs.writeFileSync(DB_FILE, JSON.stringify(this.stats, null, 2));
        } catch (e) {
            console.error("[UsageGuard] Failed to save DB:", e);
        }
    }

    public checkLimit(): { allowed: boolean; remainingBudget: number } {
        this.load(); // Sync state
        if (this.stats.estimatedCost >= this.budgetLimitUsd) {
            console.warn(`[UsageGuard] BLOCKED: Daily limit $${this.budgetLimitUsd} exceeded (Current: $${this.stats.estimatedCost.toFixed(4)})`);
            return { allowed: false, remainingBudget: 0 };
        }
        return { allowed: true, remainingBudget: this.budgetLimitUsd - this.stats.estimatedCost };
    }

    public recordUsage(inputTokens: number, outputTokens: number, model: 'flash' | 'pro' = 'flash') {
        // SAFETY: Do not record usage in test environment or if key is poisoned
        if ((process.env.NODE_ENV === 'test' && !process.env.FORCE_USAGE_RECORDING) || process.env.GEMINI_API_KEY === 'INVALID_TEST_KEY') {
            console.log(`[UsageGuard] TEST MODE: Ignoring usage record (${inputTokens}/${outputTokens})`);
            return;
        }

        this.stats.tokensInput += inputTokens;
        this.stats.tokensOutput += outputTokens;

        const inputRate = model === 'pro' ? COST_PRO_INPUT : COST_FLASH_INPUT;
        const outputRate = model === 'pro' ? COST_PRO_OUTPUT : COST_FLASH_OUTPUT;

        const cost = (inputTokens / 1_000_000 * inputRate) +
            (outputTokens / 1_000_000 * outputRate);

        this.stats.estimatedCost += cost;
        this.save();
        console.log(`[UsageGuard] Recorded (${model}): ${inputTokens} in / ${outputTokens} out. Cost: +$${cost.toFixed(6)}. Total: $${this.stats.estimatedCost.toFixed(4)}`);
    }

    public getStats() {
        // Calculate percentage of budget used
        const percentage = Math.min(100, (this.stats.estimatedCost / this.budgetLimitUsd) * 100);
        return {
            ...this.stats,
            budgetLimit: this.budgetLimitUsd,
            percentage: percentage
        };
    }
}

export const usageGuard = new UsageGuard();

